use crate::types::{DecideInput, DecideOutput};

const PI: f64 = 3.1415926535;

fn dist(x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    ((x1 - x2).powi(2) + (y1 - y2).powi(2)).sqrt()
}

fn triangle_area(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    0.5 * (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs()
}

fn realcompare(a: f64, b: f64) -> &'static str {
    if (a - b).abs() < 1e-6 {
        "EQ"
    } else if a < b {
        "LT"
    } else {
        "GT"
    }
}

fn min_enclosing_radius(x1: f64, y1: f64, x2: f64, y2: f64, x3: f64, y3: f64) -> f64 {
    let d12 = dist(x1, y1, x2, y2);
    let d23 = dist(x2, y2, x3, y3);
    let d31 = dist(x3, y3, x1, y1);

    // If triangle is obtuse or right, the smallest enclosing circle has the longest side as diameter.
    if d12 * d12 + d23 * d23 <= d31 * d31 {
        return d31 / 2.0;
    }
    if d23 * d23 + d31 * d31 <= d12 * d12 {
        return d12 / 2.0;
    }
    if d31 * d31 + d12 * d12 <= d23 * d23 {
        return d23 / 2.0;
    }

    // Acute triangle: the smallest enclosing circle is the circumcircle.
    let area = triangle_area(x1, y1, x2, y2, x3, y3);
    if area < 1e-9 {
        return d12.max(d23).max(d31) / 2.0;
    }
    (d12 * d23 * d31) / (4.0 * area)
}

fn get_quadrant(x: f64, y: f64) -> usize {
    if x >= 0.0 && y >= 0.0 {
        1
    } else if x < 0.0 && y >= 0.0 {
        2
    } else if x <= 0.0 && y < 0.0 {
        3
    } else {
        4
    }
}

fn point_to_line_dist(x0: f64, y0: f64, x1: f64, y1: f64, x2: f64, y2: f64) -> f64 {
    if realcompare(x1, x2) == "EQ" && realcompare(y1, y2) == "EQ" {
        return dist(x0, y0, x1, y1);
    }
    let num = ((y2 - y1) * x0 - (x2 - x1) * y0 + x2 * y1 - y2 * x1).abs();
    let den = ((y2 - y1).powi(2) + (x2 - x1).powi(2)).sqrt();
    num / den
}

pub fn decide(input: &DecideInput) -> DecideOutput {
    let mut cmv = [false; 15];
    let n = input.numpoints;

    // LIC 1
    for i in 0..n - 1 {
        if realcompare(dist(input.x[i], input.y[i], input.x[i + 1], input.y[i + 1]), input.parameters.length1) == "GT" {
            cmv[0] = true;
            break;
        }
    }

    // LIC 2
    for i in 0..n - 2 {
        if realcompare(min_enclosing_radius(input.x[i], input.y[i], input.x[i + 1], input.y[i + 1], input.x[i + 2], input.y[i + 2]), input.parameters.radius1) == "GT" {
            cmv[1] = true;
            break;
        }
    }

    // LIC 3
    for i in 0..n - 2 {
        let (x1, y1) = (input.x[i], input.y[i]);
        let (x2, y2) = (input.x[i + 1], input.y[i + 1]); // Vertex
        let (x3, y3) = (input.x[i + 2], input.y[i + 2]);
        if (x1 == x2 && y1 == y2) || (x3 == x2 && y3 == y2) {
            continue;
        }
        let a = dist(x2, y2, x3, y3);
        let b = dist(x1, y1, x3, y3);
        let c = dist(x1, y1, x2, y2);
        let cos_theta = (a * a + c * c - b * b) / (2.0 * a * c);
        let angle = cos_theta.max(-1.0).min(1.0).acos();
        if realcompare(angle, PI - input.parameters.epsilon) == "LT" || realcompare(angle, PI + input.parameters.epsilon) == "GT" {
            cmv[2] = true;
            break;
        }
    }

    // LIC 4
    for i in 0..n - 2 {
        if realcompare(triangle_area(input.x[i], input.y[i], input.x[i + 1], input.y[i + 1], input.x[i + 2], input.y[i + 2]), input.parameters.area1) == "GT" {
            cmv[3] = true;
            break;
        }
    }

    // LIC 5
    let q_pts = input.parameters.q_pts;
    if n >= q_pts {
        for i in 0..=n - q_pts {
            let mut quadrants = [false; 5];
            for j in 0..q_pts {
                quadrants[get_quadrant(input.x[i + j], input.y[i + j])] = true;
            }
            let count = quadrants.iter().filter(|&&b| b).count();
            if count > input.parameters.quads {
                cmv[4] = true;
                break;
            }
        }
    }

    // LIC 6
    for i in 0..n - 1 {
        if realcompare(input.x[i + 1], input.x[i]) == "LT" {
            cmv[5] = true;
            break;
        }
    }

    // LIC 7
    if n >= 3 {
        let n_pts = input.parameters.n_pts;
        for i in 0..=n - n_pts {
            for j in 1..n_pts - 1 {
                if realcompare(point_to_line_dist(input.x[i + j], input.y[i + j], input.x[i], input.y[i], input.x[i + n_pts - 1], input.y[i + n_pts - 1]), input.parameters.dist) == "GT" {
                    cmv[6] = true;
                    break;
                }
            }
            if cmv[6] { break; }
        }
    }

    // LIC 8
    if n >= 3 {
        let k_pts = input.parameters.k_pts;
        for i in 0..n - k_pts - 1 {
            if realcompare(dist(input.x[i], input.y[i], input.x[i + k_pts + 1], input.y[i + k_pts + 1]), input.parameters.length1) == "GT" {
                cmv[7] = true;
                break;
            }
        }
    }

    // LIC 9
    if n >= 5 {
        let a_pts = input.parameters.a_pts;
        let b_pts = input.parameters.b_pts;
        for i in 0..n - a_pts - b_pts - 2 {
            if realcompare(min_enclosing_radius(input.x[i], input.y[i], input.x[i + a_pts + 1], input.y[i + a_pts + 1], input.x[i + a_pts + b_pts + 2], input.y[i + a_pts + b_pts + 2]), input.parameters.radius1) == "GT" {
                cmv[8] = true;
                break;
            }
        }
    }

    // LIC 10
    if n >= 5 {
        let c_pts = input.parameters.c_pts;
        let d_pts = input.parameters.d_pts;
        for i in 0..n - c_pts - d_pts - 2 {
            let (x1, y1) = (input.x[i], input.y[i]);
            let (x2, y2) = (input.x[i + c_pts + 1], input.y[i + c_pts + 1]);
            let (x3, y3) = (input.x[i + c_pts + d_pts + 2], input.y[i + c_pts + d_pts + 2]);
            if (x1 == x2 && y1 == y2) || (x3 == x2 && y3 == y2) { continue; }
            let a = dist(x2, y2, x3, y3);
            let b = dist(x1, y1, x3, y3);
            let c = dist(x1, y1, x2, y2);
            let cos_theta = (a * a + c * c - b * b) / (2.0 * a * c);
            let angle = cos_theta.max(-1.0).min(1.0).acos();
            if realcompare(angle, PI - input.parameters.epsilon) == "LT" || realcompare(angle, PI + input.parameters.epsilon) == "GT" {
                cmv[9] = true;
                break;
            }
        }
    }

    // LIC 11
    if n >= 5 {
        let e_pts = input.parameters.e_pts;
        let f_pts = input.parameters.f_pts;
        for i in 0..n - e_pts - f_pts - 2 {
            if realcompare(triangle_area(input.x[i], input.y[i], input.x[i + e_pts + 1], input.y[i + e_pts + 1], input.x[i + e_pts + f_pts + 2], input.y[i + e_pts + f_pts + 2]), input.parameters.area1) == "GT" {
                cmv[10] = true;
                break;
            }
        }
    }

    // LIC 12
    if n >= 3 {
        let g_pts = input.parameters.g_pts;
        for i in 0..n - g_pts - 1 {
            if realcompare(input.x[i + g_pts + 1], input.x[i]) == "LT" {
                cmv[11] = true;
                break;
            }
        }
    }

    // LIC 13
    if n >= 3 {
        let k_pts = input.parameters.k_pts;
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..n - k_pts - 1 {
            let d = dist(input.x[i], input.y[i], input.x[i + k_pts + 1], input.y[i + k_pts + 1]);
            if realcompare(d, input.parameters.length1) == "GT" { part1 = true; }
            if realcompare(d, input.parameters.length2) == "LT" { part2 = true; }
        }
        cmv[12] = part1 && part2;
    }

    // LIC 14
    if n >= 5 {
        let a_pts = input.parameters.a_pts;
        let b_pts = input.parameters.b_pts;
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..n - a_pts - b_pts - 2 {
            let r = min_enclosing_radius(input.x[i], input.y[i], input.x[i + a_pts + 1], input.y[i + a_pts + 1], input.x[i + a_pts + b_pts + 2], input.y[i + a_pts + b_pts + 2]);
            if realcompare(r, input.parameters.radius1) == "GT" { part1 = true; }
            if realcompare(r, input.parameters.radius2) == "LT" || realcompare(r, input.parameters.radius2) == "EQ" { part2 = true; }
        }
        cmv[13] = part1 && part2;
    }

    // LIC 15
    if n >= 5 {
        let e_pts = input.parameters.e_pts;
        let f_pts = input.parameters.f_pts;
        let mut part1 = false;
        let mut part2 = false;
        for i in 0..n - e_pts - f_pts - 2 {
            let a = triangle_area(input.x[i], input.y[i], input.x[i + e_pts + 1], input.y[i + e_pts + 1], input.x[i + e_pts + f_pts + 2], input.y[i + e_pts + f_pts + 2]);
            if realcompare(a, input.parameters.area1) == "GT" { part1 = true; }
            if realcompare(a, input.parameters.area2) == "LT" { part2 = true; }
        }
        cmv[14] = part1 && part2;
    }

    let mut pum = [[false; 15]; 15];
    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                let op = &input.lcm[i][j];
                pum[i][j] = match op.as_str() {
                    "NOTUSED" => true,
                    "ANDD" => cmv[i] && cmv[j],
                    "ORR" => cmv[i] || cmv[j],
                    _ => true,
                };
            }
        }
    }

    let mut fuv = [false; 15];
    for i in 0..15 {
        if !input.pum_diag[i] {
            fuv[i] = true;
        } else {
            let mut all_true = true;
            for j in 0..15 {
                if !pum[i][j] {
                    all_true = false;
                    break;
                }
            }
            fuv[i] = all_true;
        }
    }

    let launch = fuv.iter().all(|&b| b);

    DecideOutput::from_fixed(cmv, pum, fuv, launch)
}
